window.__QUIZ_DATA__=[{"id":"theory>Biology>2003>1>a","subject":"Biology","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"What is a balanced diet?","images":[],"marking_scheme":"A balance diet is a diet that consist of variety of different types of food that provide adequate amounts of the nutrients needed to maintain or improve overall health. It contains all the six classes of food which are carbohydrates, protein, fat, vitamins, water and mineral salts.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2003>1>b>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Name four classes of food other than proteins.","images":[],"marking_scheme":"- Carbohydrates  - Vitamin  - Fat and oil  - Mineral salt  - Water  - Roughages","marks":"4","difficulty":"1"},{"id":"theory>Biology>2003>1>b>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Give one example of food substance for each class named.","images":[],"marking_scheme":"i. Carbohydrate: Rice, Bread, Cassava, Yam, Cocoa-yam. Potato etc.  ii. Fat and oil: Melon, Butter, Margarine, Palm oil, Soya, Beans e.t.c  iii. Vitamin: Fruits, egg, milk, liver oil, vegetables e.t.c.  iv. Mineral Salt: Fruits (orange, banana, mango e.t.c), vegetables, bones, egg, table salt etc.  v. Water: Water in plants, water in animal, water from all sources for drinking, water in food, beverages.  vi. Roughages: whole grains like oats and vegetables like carrot and cucumber.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2003>1>c>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"State three functions of proteins in humans.","images":[],"marking_scheme":"The functions of protein in the body are:  - It helps in repairing and maintenance of body tissue, including development. For example, Hair, Skin, eyes, muscles and organs are made from protein.    - Protein is a major source of energy.    - It is involved in the creation of some hormones which involves the interaction of several organs.    - Enzymes are protein that increases the rate of chemical reaction in the body.    - Protein is a major element in transportation of certain molecules. It sometimes stores certain molecules.    - Protein forms antibodies that help prevent infection, illness and disease.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>1>c>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Describe the appearance of a child with protein deficiency.","images":[],"marking_scheme":"The child will have retarded, poor and stunted growth. The child will have oedema with swollen legs and feet. The child will lose weight with cracked skin. The child will have kwashiorkor with swollen stomach. The limbs of the child may become thin with reddish brown hair with pale body.","marks":"2","difficulty":"3"},{"id":"theory>Biology>2003>1>d>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Name one organelle in a living cell that produces enzymes.","images":[],"marking_scheme":"The name of an organelle in a living cell that produces enzymes is Ribosomes.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2003>1>d>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Mention two enzymes that act on proteins.","images":[],"marking_scheme":"The enzymes that act on proteins are the pepsin, Renin and Trypsin.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>2>a","subject":"Biology","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Describe the processes that occur from the time a pollen grain is deposited on the stigma of a flower to the formation of a zygote.","images":[],"marking_scheme":"The processes that occur from the time a pollen grain is deposited on the stigma of a flower to the formation of a zygote.  Flowering plant generate pollen grain which is transfer to the stigma to absorb sugary material and bursts. The pollen tube emerges carrying a tube nucleus and a generative nucleus. The generative nucleus divides to form two male nuclei (male gametes). The pollen tube grows down the style deriving energy and food from its tissues. When the nuclei are about reaching the ovary, the pollen tube nucleus disintegrates. The two male nuclei are released into the ovule through the micropyle. When the pollen grain reaches the embryo sac, it discharges its contents into the sac. One of the male gametes fuses with the egg cell (ovum) to form zygote while the other gamete fuses with the polar nuclei to form endosperm.","marks":"7.5","difficulty":"3"},{"id":"theory>Biology>2003>2>b","subject":"Biology","year":"2003","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Explain the importance of the amniotic sac to the mammalian embryo.","images":[],"marking_scheme":"The amniotic sac contains amniotic fluid which provides a constant warm temperature for the foetus. The amniotic fluid in the sac also provides a sterile environment for the developing embryo. There is a free movement of the foetus allowed by the fluid. The fluid also provide protection by acting as shock absorber during mechanical injury.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2003>2>c","subject":"Biology","year":"2003","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"The following are the names of some common diseases, malaria, typhoid, amoeboid dysentry, tuberculosis, tetanus, leprosy, cholera, yellow fever, polio myelitis, measles, common cold, small pox, influenza, chicken pox, whooping cough and trypanosomiasis.    Use the format below to classify the diseases according to their causative organisms  Viral Diseases Bacterial Diseases Protozoan Diseases","images":[],"marking_scheme":"VirusesBacteriaProtozoanYellow feverTetanusMalariaPoliomyelitisTyphoidTrypanosomiasisMeaslesTuberculosisAmoeboid dysentaryChicken poxLeprosy Common coldCholera Small pox Whooping cough Influenza","marks":"7.5","difficulty":"3"},{"id":"theory>Biology>2003>3>a>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"What is respiration?","images":[],"marking_scheme":"Respiration is the process in living organisms involving the production of energy, typically with the intake of oxygen and the release of carbondioxide from the oxidation of complex organic substances.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2003>3>a>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Name two types of respirations.","images":[],"marking_scheme":"- Aerobic respiration  - Anaerobic respiration","marks":"2","difficulty":"1"},{"id":"theory>Biology>2003>3>a>iii","subject":"Biology","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Write in words the equation representing the type of respiration that occurs in the muscle during strenuous exercise.","images":[],"marking_scheme":"The word equation for respiration in muscles during exercise:  Glucose \u2192 Lactic acid + Water + Energy (ATP)","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>3>b>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Make a large labelled diagram 8cm to 10cm of the human respiratory system show the internal structures.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"3"},{"id":"theory>Biology>2003>3>b>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Name two diseases that can affect the above mentioned system.","images":[],"marking_scheme":"The diseases of the lungs include the lung cancer, tuberculosis, pneumonia, bronchitis, asthma, common cold, whooping cough, SARS and influenza.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>3>c>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Mention the structures used for gaseous exchange in this organism    Amoeba","images":[],"marking_scheme":"It uses the body surface.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2003>3>c>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Mention the structures used for gaseous exchange in this organism  Cockroach","images":[],"marking_scheme":"It uses the trachea.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>3>c>iii","subject":"Biology","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Mention the structures used for gaseous exchange in this organism  White mangrove","images":[],"marking_scheme":"It uses pneumatophores (breathing roots) or lenticels or stomata.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>3>c>iv","subject":"Biology","year":"2003","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Mention the structures used for gaseous exchange in this organism  Hibiscus","images":[],"marking_scheme":"It uses stomata or lenticels.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>4>a","subject":"Biology","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL THEORY","question":"What is a cell?","images":[],"marking_scheme":"A cell is the smallest structural and functional unit of an organism, which is typically microscopic and consists of cytoplasm and a nucleus enclosed in a membrane.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2003>4>b>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Describe the structure and state the function of each this    Nucleus","images":[],"marking_scheme":"The nucleus is a rounded body often located at the centre of the cytoplasm of the cell. It is covered by a double membrane called nuclear membrane and contains DNA, nucleolus and nucleoplasm. The nucleus performs the function of controlling the activities of the cell such as protein and enzyme synthesis and also initiates cell division.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2003>4>b>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Describe the structure and state the function of each this  Mitochondrion","images":[],"marking_scheme":"This is rod or boat like in structure and bounded by double membrane. The inner membrane is folded to form cristae while the anterior is filled with matrix, which contains ribosomes and phosphate granules. The mitochondrion performs the function of tissue respiration in the cell.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2003>4>c>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"Make a labelled diagram 8cm to 10cm long of the Euglena.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"6","difficulty":"3"},{"id":"theory>Biology>2003>4>c>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"List three animal-like features and two plant like features of Euglena.","images":[],"marking_scheme":"The animal-like features of the Euglena are:  i. Possession of flagellum for locomotion.  ii. Possession of pellicle to aid movement.  iii. Possession of eye-spot for response to light.  iv. Presence of contractile vacuole for excretion.    The plant-like features of the Euglena are:  i. possession of pyrenoid  ii. Possession of chloroplast for photosynthesis  iii. Possession of cellwall  iv. It has paramylum granules for storing starch.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2003>5>a","subject":"Biology","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"Name three main parts of the human brain.","images":[],"marking_scheme":"-Forebrain (Prosencephalon): Cerebrum, thalamus, hypothalamus  -Midbrain (Mesencephalon): Tectum, tegmentum  -Hindbrain (Rhombencephalon): Cerebellum, pons, medulla oblongata","marks":"2","difficulty":"1"},{"id":"theory>Biology>2003>5>b>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"State the functions of the Cerebrum.","images":[],"marking_scheme":"The cerebrum, the largest part of the human brain, is responsible for various higher brain functions, including:    -Sensory Perception: Processing and interpreting sensory information such as vision, hearing, touch, taste, and smell.  -Motor Control: Planning, initiating, and controlling voluntary movements.  -Cognition: Involving functions like thinking, reasoning, problem-solving, decision-making, and planning.  -Memory: Storing and retrieving information.  -Emotion: Regulating and experiencing emotions.  -Language: Comprehending and producing speech and language.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>5>b>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"State the functions of the Hypothalamus.","images":[],"marking_scheme":"The hypothalamus is a small but crucial part of the brain that plays a key role in many important functions, including:    -Regulating Body Temperature: The hypothalamus acts as the body's thermostat, maintaining a stable internal temperature.  -Controlling Appetite and Thirst: It regulates hunger and thirst signals, helping to maintain energy balance and hydration.  -Managing Stress Responses: The hypothalamus initiates the body's response to stress through the release of cortisol and other stress hormones.  -Regulating Sleep-Wake Cycles: It helps control circadian rhythms, influencing sleep patterns and wakefulness.  -Releasing Hormones: The hypothalamus produces and releases hormones that regulate the pituitary gland, which in turn controls other endocrine glands in the body.  -Regulating Emotional Responses: It is involved in emotional regulation and behaviors such as aggression and pleasure.  -Controlling Autonomic Functions: The hypothalamus oversees autonomic functions such as heart rate, blood pressure, and digestion.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>5>b>iii","subject":"Biology","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"State the functions of Medulla Oblongata.","images":[],"marking_scheme":"The medulla oblongata helps regulate breathing heart and blood vessel function, digestion, sneezing, and swallowing. This part of the brain is a centre for respiration and circulation. Sensory and motor neutrons (nerve cells) from the forebrain and midbrain travel through the medulla.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>5>c>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"List three organs of a higher plant that can respond to stimulus.","images":[],"marking_scheme":"The parts of higher plants that responds to stimuli are   - The flowers  - The leaves  - The root  - The stem  - The tendril","marks":"3","difficulty":"2"},{"id":"theory>Biology>2003>5>c>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"What is tactic movement?","images":[],"marking_scheme":"Tactic movement is the movement of the entire body of an organism in response to stimulus. It is a directional movement that could be positive or negative.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2003>5>d>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"Explain this term, giving one example    Phototaxis","images":[],"marking_scheme":"It is the movement in response to light stimulus by an organism e.g Euglena.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2003>5>d>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"Explain this term, giving one example   Hydrotaxis","images":[],"marking_scheme":"It is the movement of whole organism in response to the stimulus of water or humidity e.g Woodhouse.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>5>d>iii","subject":"Biology","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"Explain this term, giving one example   Chemotaxis","images":[],"marking_scheme":"It is the movement of whole organism in response to chemical stimulus e.g sperm, paramecium, amoeba.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2003>6>a","subject":"Biology","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"List four adaptive features of animals that climb rain forest trees.","images":[],"marking_scheme":"The adaptive features of animals that climb rain forest trees are;  - They have sticky or adhesive discs on their fingers e.g geckos.  - They have prehensile tails e.g monkey  - They have opposable digits.  - They have grasping seales e.g snakes. Some have grasping ponds e.g tree frogs. Some have long sharp claws for climbing e.g squirrels.","marks":"4","difficulty":"3"},{"id":"theory>Biology>2003>6>b","subject":"Biology","year":"2003","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"State five important uses of water to organisms in the tropical rain forest.","images":[],"marking_scheme":"- Water helps to maintain body temperature of organisms.  - Moisture in form of water is essential for burrowing animals.  - It is essential for movement and survival of aquatic animals.  - Water or moisture is necessary for microbial activity.  - It is essential for photosynthesis.  - It is essential for translocation.  - Water helps in metabolism of organisms.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2003>6>c","subject":"Biology","year":"2003","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"Describe how temperature as an ecological factor can be measured.","images":[],"marking_scheme":"The process of measuring temperature: The instrument used is the thermometer. The bulb of the instrument is suspended in the medium whose temperature is to be measured for about five minutes and the level of the stem is read and recorded. About three readings are recorded and the average is found.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2003>6>d>i","subject":"Biology","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Name two scientists who have contributed to the study of evolution.","images":[],"marking_scheme":"- Jean Larmack  - Charles Darwin  - De'Vries  - A. R. Wallace","marks":"3","difficulty":"1"},{"id":"theory>Biology>2003>6>d>ii","subject":"Biology","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"List five evidences to support the occurrence of evolution.","images":[],"marking_scheme":"- The evidence from comparative morphology.  - The evidence from comparative anatomy.  - The physiological evidence.  - The evidence from vestigial organs.  - The evidence from cytology.  - The evidence from fossil records.  - The physiological evidence.","marks":"5","difficulty":"2"}];